def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, fill_value=np.nan, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = float('inf')
            continue
        ratio = item / capacity
        score = 0
        if ratio < 0.05:
            for a1 in range(1, 5):
                inner_sum = 0
                for b1 in range(1, 8):
                    val = np.sin(ratio * a1 * b1) * (b1 ** 1.8) / (a1 + 2)
                    if val < 0:
                        val = abs(val) * 0.7
                    else:
                        val *= 1.1
                    inner_sum += val
                if inner_sum > 5:
                    inner_sum /= 3.5
                score += inner_sum
            if (capacity + item) % 4 == 0 and (capacity - item) % 6 == 0:
                score *= 0.75
            if score > 12:
                score /= 3
        elif 0.05 <= ratio < 0.25:
            prod = 1
            for n1 in range(1, int(capacity) + 3):
                factor = ratio + (n1**0.7) / (n1 + 2)
                prod *= factor
                if prod > 1e5:
                    prod = np.log1p(prod) * 1.5
                    break
            mod_val = int(prod * 7) % 400
            score += np.cbrt(ratio * mod_val + 2)
            if (int(capacity) % 5 == 0) or ((item * 3) % 4 == 0):
                score += 5.3
            else:
                score -= 1.1
            extra_sum = 0
            for x1 in range(1, 7):
                extra_sum += ((ratio * x1**1.9) % 1) * (x1 ** 1.9)
            score += extra_sum / 6
            if score > 18:
                score /= 3.2
        elif 0.25 <= ratio <= 0.55:
            for m1 in range(1, 9):
                increment = (ratio ** (m1 + 1.5)) * (m1 ** 3.1) / ((m1 + 1.5) ** 1.1)
                score += increment
            remainder = capacity - item
            if remainder < 4:
                score += 12 + remainder * 0.7
            else:
                score -= remainder * 0.85
            if score < -4:
                score = abs(score) * 0.28 + 3
            if int(capacity) % 8 == 0:
                score *= 1.15
            if score > 20:
                score /= 3.5
        elif 0.55 < ratio <= 0.9:
            penalty_base = 0
            for p1 in range(1, 12):
                term = ((ratio - 0.55) ** p1) * (p1 ** 1.7)
                penalty_base += term
                if penalty_base > 60:
                    penalty_base = np.log1p(penalty_base) * 1.3
                    break
            score = penalty_base * 14
            if capacity < item * 1.03:
                score += 20
            if (int(capacity * 6) % 8 == 0) and (int(item * 7) % 13 == 0):
                score -= 7
            if score < 0:
                score *= -1.7
                score += 7
            if score > 130:
                score = 130
        elif 0.9 < ratio <= 1.4:
            penalty_ext = 0
            diff = ratio - 0.9
            for q1 in range(1, 14):
                penalty_ext += ((diff) ** q1) * (q1 ** 2.8) / (q1 + 2)
                if penalty_ext > 1500:
                    penalty_ext = np.log1p(penalty_ext) * 3
                    break
            score = penalty_ext * 18
            if capacity < item * 1.35:
                score += 22
            if (int(capacity * 2) % 6 == 0) or (int(item * 10) % 7 == 0):
                score -= 8
            for z1 in range(1, 7):
                score += ((diff / (z1 + 0.7)) % 1) * (z1 * 1.8)
            if score < 0:
                score = abs(score) * 0.45
            if score > 1500:
                score = 1500
        else:
            super_penalty = 0
            diff = ratio - 1.4
            for r1 in range(1, 15):
                term = ((diff) ** r1) * (r1 ** 3.5)
                if term > 15000:
                    term = np.cbrt(term) * 2
                super_penalty += term
            score = super_penalty * 30
            if capacity < item * 2.5:
                score += 30
            if (int(capacity * 11) % 5 == 0) and (int(item * 19) % 6 == 0):
                score -= 12
            for w1 in range(3, 9):
                score += ((diff / w1) % 1) * (w1 * 2.4)
            if score < 0:
                score = abs(score) * 0.7 + 5
            if score > 2500:
                score = 2500
        if capacity > 300:
            score /= (np.log1p(capacity) + 1.5)
            if score < 1:
                score += 0.5 * np.tanh(ratio * 3)
        elif capacity < 8:
            score *= 2.8
            if score > 2500:
                score = 2500
        if abs(score) > 1800:
            score = np.sign(score) * 1800
        priorities[i] = score
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size == 0:
        fill_value = 0
    else:
        quartiles = np.percentile(finite_priorities, [20, 50, 80])
        top_count = np.sum(finite_priorities > quartiles[2])
        median_val = quartiles[1]
        fill_value = np.max(finite_priorities) * (20 + top_count) - median_val * 1.1
    priorities[np.isinf(priorities)] = fill_value
    median_val = np.median(finite_priorities) if finite_priorities.size > 0 else 0
    for idx in range(len(priorities)):
        if np.isnan(priorities[idx]):
            priorities[idx] = median_val
    return priorities
